import{_ as e,c as t,o as a,a5 as r}from"./chunks/framework.DwbewbAn.js";const b=JSON.parse('{"title":"多集群管理","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/multicluster.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/multicluster.md","lastUpdated":1705214817000}'),l={name:"doc/DevOps/Kubernetes/基础/multicluster.md"},i=r('<h1 id="多集群管理" tabindex="-1">多集群管理 <a class="header-anchor" href="#多集群管理" aria-label="Permalink to &quot;多集群管理&quot;">​</a></h1><p>组织需要部署多个 Kubernetes 集群来为不同的业务提供隔离，增强可用性和可扩展性。</p><h2 id="什么是多集群" tabindex="-1">什么是多集群？ <a class="header-anchor" href="#什么是多集群" aria-label="Permalink to &quot;什么是多集群？&quot;">​</a></h2><p>多集群是一种在多个 Kubernetes 集群上或跨集群部署应用的策略，目的是提高可用性、隔离性和可扩展性。多集群对于确保遵守不同的和相互冲突的法规非常重要，因为单个集群可以进行调整，以遵守特定地域或认证的法规。软件交付的速度和安全性也可以提高，单个开发团队将应用程序部署到隔离的集群中，并有选择地暴露哪些服务可用于测试和发布。</p><h2 id="配置多集群访问" tabindex="-1">配置多集群访问 <a class="header-anchor" href="#配置多集群访问" aria-label="Permalink to &quot;配置多集群访问&quot;">​</a></h2><p>你可以使用 <code>kubectl config</code> 命令配置要访问的集群，详见<a href="https://kubernetes.io/zh/docs/tasks/access-application-cluster/configure-access-multiple-clusters/" target="_blank" rel="noreferrer">配置对多集群的访问</a>。</p><h2 id="集群联邦" tabindex="-1">集群联邦 <a class="header-anchor" href="#集群联邦" aria-label="Permalink to &quot;集群联邦&quot;">​</a></h2><p>集群联邦（Federation）是指通过 Federation API 资源来统一管理多个集群的资源，如定义 Deployment 如何部署到不同集群上，及其所需的副本数等。这些集群可能位于不同的可用区、地区或者供应商。实施集群联邦一般是为了达到以下目的：</p><ul><li>简化管理多个集群的 Kubernetes 组件 (如 Deployment、Service 等）；</li><li>在多个集群之间分散工作负载（Pod），以提升应用（服务）的可靠性；</li><li>跨集群的资源编排，依据编排策略在多个集群进行应用（服务）部署；</li><li>在不同集群中，能更快速更容易地迁移应用（服务）；</li><li>跨集群的服务发现，服务可以提供给当地存取，以降低延迟；</li><li>实践多云（Multi-cloud）或混合云（Hybird Cloud）的部署；</li></ul><p>更多内容请见<a href="./../practice/federation">集群联邦</a>。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://github.com/kubernetes/community/blob/master/sig-multicluster/README.md" target="_blank" rel="noreferrer">Multicluster Special Interest Group - github.com</a></li><li><a href="https://kubernetes.io/zh/docs/tasks/access-application-cluster/configure-access-multiple-clusters/" target="_blank" rel="noreferrer">配置对多集群的访问 - kubernetes.io</a></li></ul>',12),s=[i];function o(c,n,u,d,h,p){return a(),t("div",null,s)}const m=e(l,[["render",o]]);export{b as __pageData,m as default};
